    10→/// {@category Foundation}
    11→@immutable
    12→class OiButtonThemeData {
    13→  /// Creates an [OiButtonThemeData].
    14→  const OiButtonThemeData({this.borderRadius, this.padding, this.textStyle});
    15→
    16→  /// The corner radius applied to button shapes.
    17→  final BorderRadius? borderRadius;
    18→
    19→  /// The internal padding of the button.
    20→  final EdgeInsets? padding;
    21→
    22→  /// The text style for button labels.
    23→  final TextStyle? textStyle;
    24→
    25→  /// Creates a copy with optionally overridden values.
    26→  OiButtonThemeData copyWith({
