import 'package:flutter/painting.dart';
import 'package:flutter/widgets.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:obers_ui/obers_ui.dart';

void main() {
  // ── ST1: OiColorScheme.chart ─────────────────────────────────────────────

  group('OiColorScheme.chart', () {
    test('light() has non-empty chart list', () {
      final scheme = OiColorScheme.light();
      expect(scheme.chart, isNotEmpty);
    });

    test('dark() has non-empty chart list', () {
      final scheme = OiColorScheme.dark();
      expect(scheme.chart, isNotEmpty);
    });

    test('copyWith(chart: [...]) replaces chart colors', () {
      final scheme = OiColorScheme.light();
      const newChart = [Color(0xFFFF0000), Color(0xFF00FF00)];
      final updated = scheme.copyWith(chart: newChart);
      expect(updated.chart, equals(newChart));
    });

    test('copyWith without chart preserves original chart', () {
      final scheme = OiColorScheme.light();
      final updated = scheme.copyWith(background: const Color(0xFF123456));
      expect(updated.chart, equals(scheme.chart));
    });

    test('lerp interpolates chart list (same length)', () {
      final a = OiColorScheme.light();
      final b = OiColorScheme.dark();
      final lerped = OiColorScheme.lerp(a, b, 0.5);
      expect(lerped.chart.length, equals(a.chart.length));
    });

    test('lerp at t=0 equals a chart', () {
      final a = OiColorScheme.light();
      final b = OiColorScheme.dark();
      final lerped = OiColorScheme.lerp(a, b, 0.0);
      expect(lerped.chart, equals(a.chart));
    });

    test('lerp at t=1 equals b chart', () {
      final a = OiColorScheme.light();
      final b = OiColorScheme.dark();
      final lerped = OiColorScheme.lerp(a, b, 1.0);
      expect(lerped.chart, equals(b.chart));
    });
  });

  // ── ST2: OiThemeExt ───────────────────────────────────────────────────────

  group('OiThemeExt', () {
    testWidgets('context.oiTheme returns OiThemeData', (tester) async {
      OiThemeData? captured;

      await tester.pumpWidget(
        OiTheme(
          data: OiThemeData.light(),
          child: Builder(
            builder: (context) {
              captured = context.oiTheme;
              return const SizedBox();
            },
          ),
        ),
      );

      expect(captured, isNotNull);
      expect(captured, isA<OiThemeData>());
    });

    testWidgets('context.oiColors returns OiColorScheme', (tester) async {
      OiColorScheme? captured;

      await tester.pumpWidget(
        OiTheme(
          data: OiThemeData.light(),
          child: Builder(
            builder: (context) {
              captured = context.oiColors;
              return const SizedBox();
            },
          ),
        ),
      );

      expect(captured, isNotNull);
      expect(captured, isA<OiColorScheme>());
    });
  });

  // ── ST3: OiThemeData.performanceConfig ───────────────────────────────────

  group('OiThemeData.performanceConfig', () {
    test('light() has performanceConfig field', () {
      final theme = OiThemeData.light();
      expect(theme.performanceConfig, isNotNull);
      expect(theme.performanceConfig, isA<OiPerformanceConfig>());
    });

    test('dark() has performanceConfig field', () {
      final theme = OiThemeData.dark();
      expect(theme.performanceConfig, isNotNull);
    });

    test('light() defaults to high performance config', () {
      final theme = OiThemeData.light();
      expect(theme.performanceConfig.disableBlur, isFalse);
      expect(theme.performanceConfig.disableShadows, isFalse);
      expect(theme.performanceConfig.reduceAnimations, isFalse);
    });

    test('light() accepts custom performanceConfig', () {
      const config = OiPerformanceConfig.low();
      final theme = OiThemeData.light(performanceConfig: config);
      expect(theme.performanceConfig, equals(config));
    });

    test('dark() accepts custom performanceConfig', () {
      const config = OiPerformanceConfig.mid();
      final theme = OiThemeData.dark(performanceConfig: config);
      expect(theme.performanceConfig, equals(config));
    });

    test('copyWith(performanceConfig: ...) replaces config', () {
      final theme = OiThemeData.light();
      const newConfig = OiPerformanceConfig.low();
      final updated = theme.copyWith(performanceConfig: newConfig);
      expect(updated.performanceConfig, equals(newConfig));
    });

    test('copyWith without performanceConfig preserves original', () {
      const config = OiPerformanceConfig.low();
      final theme = OiThemeData.light(performanceConfig: config);
      final updated = theme.copyWith(fontFamily: 'Roboto');
      expect(updated.performanceConfig, equals(config));
    });

    test('merge propagates performanceConfig from other', () {
      final base = OiThemeData.light();
      const config = OiPerformanceConfig.low();
      final override = OiThemeData.light(performanceConfig: config);
      final merged = base.merge(override);
      expect(merged.performanceConfig, equals(config));
    });

    test('lerp at t=0 uses a.performanceConfig', () {
      const configA = OiPerformanceConfig.high();
      const configB = OiPerformanceConfig.low();
      final a = OiThemeData.light(performanceConfig: configA);
      final b = OiThemeData.light(performanceConfig: configB);
      final lerped = OiThemeData.lerp(a, b, 0.0);
      expect(lerped.performanceConfig, equals(configA));
    });

    test('lerp at t=1 uses b.performanceConfig', () {
      const configA = OiPerformanceConfig.high();
      const configB = OiPerformanceConfig.low();
      final a = OiThemeData.light(performanceConfig: configA);
      final b = OiThemeData.light(performanceConfig: configB);
      final lerped = OiThemeData.lerp(a, b, 1.0);
      expect(lerped.performanceConfig, equals(configB));
    });

    test('lerp at t=0.5 uses b.performanceConfig (t >= 0.5)', () {
      const configA = OiPerformanceConfig.high();
      const configB = OiPerformanceConfig.low();
      final a = OiThemeData.light(performanceConfig: configA);
      final b = OiThemeData.light(performanceConfig: configB);
      final lerped = OiThemeData.lerp(a, b, 0.5);
      expect(lerped.performanceConfig, equals(configB));
    });

    test('fromBrand() accepts performanceConfig', () {
      const config = OiPerformanceConfig.mid();
      final theme = OiThemeData.fromBrand(
        color: const Color(0xFF2563EB),
        performanceConfig: config,
      );
      expect(theme.performanceConfig, equals(config));
    });

    test('equality considers performanceConfig', () {
      final a = OiThemeData.light(
        performanceConfig: const OiPerformanceConfig.high(),
      );
      final b = OiThemeData.light(
        performanceConfig: const OiPerformanceConfig.low(),
      );
      expect(a == b, isFalse);
    });

    test('hashCode differs when performanceConfig differs', () {
      final a = OiThemeData.light(
        performanceConfig: const OiPerformanceConfig.high(),
      );
      final b = OiThemeData.light(
        performanceConfig: const OiPerformanceConfig.low(),
      );
      expect(a.hashCode == b.hashCode, isFalse);
    });
  });

  // ── ST5: OiButtonThemeScope ───────────────────────────────────────────────

  group('OiButtonThemeScope', () {
    testWidgets('provides OiButtonThemeData to descendants', (tester) async {
      const buttonTheme = OiButtonThemeData(
        borderRadius: BorderRadius.zero,
      );
      OiButtonThemeData? captured;

      await tester.pumpWidget(
        OiButtonThemeScope(
          theme: buttonTheme,
          child: Builder(
            builder: (context) {
              captured = OiButtonThemeScope.of(context);
              return const SizedBox();
            },
          ),
        ),
      );

      expect(captured, equals(buttonTheme));
    });

    testWidgets('of(context) returns null when no ancestor', (tester) async {
      OiButtonThemeData? Function()? capturedFn;

      await tester.pumpWidget(
        Builder(
          builder: (context) {
            capturedFn = () => OiButtonThemeScope.of(context);
            return const SizedBox();
          },
        ),
      );

      expect(capturedFn?.call(), isNull);
    });

    testWidgets('nested scope overrides ancestor scope', (tester) async {
      const outerTheme = OiButtonThemeData(borderRadius: BorderRadius.zero);
      const innerTheme = OiButtonThemeData(
        borderRadius: BorderRadius.zero,
        padding: EdgeInsets.all(8),
      );
      OiButtonThemeData? captured;

      await tester.pumpWidget(
        OiButtonThemeScope(
          theme: outerTheme,
          child: OiButtonThemeScope(
            theme: innerTheme,
            child: Builder(
              builder: (context) {
                captured = OiButtonThemeScope.of(context);
                return const SizedBox();
              },
            ),
          ),
        ),
      );

      expect(captured, equals(innerTheme));
    });

    testWidgets('updateShouldNotify triggers rebuild on theme change',
        (tester) async {
      int buildCount = 0;

      Widget build(OiButtonThemeData theme) {
        return OiButtonThemeScope(
          theme: theme,
          child: Builder(
            builder: (context) {
              OiButtonThemeScope.of(context);
              buildCount++;
              return const SizedBox();
            },
          ),
        );
      }

      await tester.pumpWidget(build(const OiButtonThemeData()));
      final countAfterFirst = buildCount;

      await tester.pumpWidget(
        build(const OiButtonThemeData(borderRadius: BorderRadius.zero)),
      );

      expect(buildCount, greaterThan(countAfterFirst));
    });
  });
}

import 'package:flutter/foundation.dart';
import 'package:flutter/painting.dart';

import 'package:obers_ui/src/foundation/theme/oi_color_swatch.dart';

/// A complete semantic color palette for the Obers UI design system.
///
/// [OiColorScheme] holds all color tokens used by Obers UI widgets — semantic
/// swatches (primary, accent, success, warning, error, info), surface / overlay
/// colors, text colors, border colors, glass-effect colors, and a categorical
/// chart palette.
///
/// Two built-in palettes are provided via factory constructors:
/// - [OiColorScheme.light] — a light-background palette.
/// - [OiColorScheme.dark] — a dark-background palette.
///
/// Instances are immutable; use [copyWith] to derive a modified copy or
/// [OiColorScheme.lerp] to animate between two schemes.
///
/// {@category Foundation}
@immutable
class OiColorScheme {
  /// Creates an [OiColorScheme] with all color fields specified explicitly.
  const OiColorScheme({
    required this.primary,
    required this.accent,
    required this.success,
    required this.warning,
    required this.error,
    required this.info,
    required this.background,
    required this.surface,
    required this.surfaceHover,
    required this.surfaceActive,
    required this.surfaceSubtle,
    required this.overlay,
    required this.text,
    required this.textSubtle,
    required this.textMuted,
    required this.textInverse,
    required this.textOnPrimary,
    required this.border,
    required this.borderSubtle,
    required this.borderFocus,
    required this.borderError,
    required this.glassBackground,
    required this.glassBorder,
    required this.chart,
  });

  /// A light-background color scheme.
  ///
  /// Uses a blue primary, teal accent, and light grey surfaces.
  factory OiColorScheme.light() {
    return OiColorScheme(
      primary: OiColorSwatch.from(const Color(0xFF2563EB)),
      accent: OiColorSwatch.from(const Color(0xFF0D9488)),
      success: OiColorSwatch.from(const Color(0xFF16A34A)),
      warning: OiColorSwatch.from(const Color(0xFFD97706)),
      error: OiColorSwatch.from(const Color(0xFFDC2626)),
      info: OiColorSwatch.from(const Color(0xFF0284C7)),
      background: const Color(0xFFF9FAFB),
      surface: const Color(0xFFFFFFFF),
      surfaceHover: const Color(0xFFF3F4F6),
      surfaceActive: const Color(0xFFE5E7EB),
      surfaceSubtle: const Color(0xFFF9FAFB),
      overlay: const Color(0x66000000),
      text: const Color(0xFF111827),
      textSubtle: const Color(0xFF374151),
      textMuted: const Color(0xFF6B7280),
      textInverse: const Color(0xFFFFFFFF),
      textOnPrimary: const Color(0xFFFFFFFF),
      border: const Color(0xFFD1D5DB),
      borderSubtle: const Color(0xFFE5E7EB),
      borderFocus: const Color(0xFF2563EB),
      borderError: const Color(0xFFDC2626),
      glassBackground: const Color(0x99FFFFFF),
      glassBorder: const Color(0x33FFFFFF),
      chart: const [
        Color(0xFF2563EB),
        Color(0xFF0D9488),
        Color(0xFFD97706),
        Color(0xFFDC2626),
        Color(0xFF7C3AED),
        Color(0xFF0284C7),
        Color(0xFF16A34A),
        Color(0xFFDB2777),
      ],
    );
  }

  /// A dark-background color scheme.
  ///
  /// Uses a blue primary, teal accent, and near-black surfaces.
  factory OiColorScheme.dark() {
    return OiColorScheme(
      primary: OiColorSwatch.from(const Color(0xFF3B82F6)),
      accent: OiColorSwatch.from(const Color(0xFF14B8A6)),
      success: OiColorSwatch.from(const Color(0xFF22C55E)),
      warning: OiColorSwatch.from(const Color(0xFFF59E0B)),
      error: OiColorSwatch.from(const Color(0xFFEF4444)),
      info: OiColorSwatch.from(const Color(0xFF38BDF8)),
      background: const Color(0xFF0A0A0F),
      surface: const Color(0xFF111118),
      surfaceHover: const Color(0xFF1C1C26),
      surfaceActive: const Color(0xFF252533),
      surfaceSubtle: const Color(0xFF0D0D14),
      overlay: const Color(0x99000000),
      text: const Color(0xFFF9FAFB),
      textSubtle: const Color(0xFFD1D5DB),
      textMuted: const Color(0xFF9CA3AF),
      textInverse: const Color(0xFF111827),
      textOnPrimary: const Color(0xFFFFFFFF),
      border: const Color(0xFF374151),
      borderSubtle: const Color(0xFF1F2937),
      borderFocus: const Color(0xFF3B82F6),
      borderError: const Color(0xFFEF4444),
      glassBackground: const Color(0x33FFFFFF),
      glassBorder: const Color(0x1AFFFFFF),
      chart: const [
        Color(0xFF3B82F6),
        Color(0xFF14B8A6),
        Color(0xFFF59E0B),
        Color(0xFFEF4444),
        Color(0xFF8B5CF6),
        Color(0xFF38BDF8),
        Color(0xFF22C55E),
        Color(0xFFF472B6),
      ],
    );
  }

  /// Linearly interpolates between two [OiColorScheme]s.
  ///
  /// [t] must be in the range [0, 1]. At [t] = 0 the result equals [a];
  /// at [t] = 1 the result equals [b].
  OiColorScheme.lerp(OiColorScheme a, OiColorScheme b, double t)
    : primary = OiColorSwatch.lerp(a.primary, b.primary, t),
      accent = OiColorSwatch.lerp(a.accent, b.accent, t),
      success = OiColorSwatch.lerp(a.success, b.success, t),
      warning = OiColorSwatch.lerp(a.warning, b.warning, t),
      error = OiColorSwatch.lerp(a.error, b.error, t),
      info = OiColorSwatch.lerp(a.info, b.info, t),
      background = Color.lerp(a.background, b.background, t)!,
      surface = Color.lerp(a.surface, b.surface, t)!,
      surfaceHover = Color.lerp(a.surfaceHover, b.surfaceHover, t)!,
      surfaceActive = Color.lerp(a.surfaceActive, b.surfaceActive, t)!,
      surfaceSubtle = Color.lerp(a.surfaceSubtle, b.surfaceSubtle, t)!,
      overlay = Color.lerp(a.overlay, b.overlay, t)!,
      text = Color.lerp(a.text, b.text, t)!,
      textSubtle = Color.lerp(a.textSubtle, b.textSubtle, t)!,
      textMuted = Color.lerp(a.textMuted, b.textMuted, t)!,
      textInverse = Color.lerp(a.textInverse, b.textInverse, t)!,
      textOnPrimary = Color.lerp(a.textOnPrimary, b.textOnPrimary, t)!,
      border = Color.lerp(a.border, b.border, t)!,
      borderSubtle = Color.lerp(a.borderSubtle, b.borderSubtle, t)!,
      borderFocus = Color.lerp(a.borderFocus, b.borderFocus, t)!,
      borderError = Color.lerp(a.borderError, b.borderError, t)!,
      glassBackground = Color.lerp(a.glassBackground, b.glassBackground, t)!,
      glassBorder = Color.lerp(a.glassBorder, b.glassBorder, t)!,
      chart = List<Color>.generate(
        a.chart.length,
        (i) => Color.lerp(
          a.chart[i],
          b.chart[i < b.chart.length ? i : b.chart.length - 1],
          t,
        )!,
      );

  // ── Semantic swatches ────────────────────────────────────────────────────

  /// The primary brand color swatch (base, light, dark, muted, foreground).
  final OiColorSwatch primary;

  /// The accent / secondary brand color swatch.
  final OiColorSwatch accent;

  /// The success / positive state color swatch.
  final OiColorSwatch success;

  /// The warning / caution state color swatch.
  final OiColorSwatch warning;

  /// The error / destructive state color swatch.
  final OiColorSwatch error;

  /// The informational state color swatch.
  final OiColorSwatch info;

  // ── Background / surface ─────────────────────────────────────────────────

  /// The app-level page background color.
  final Color background;

  /// The default card / panel surface color.
  final Color surface;

  /// Surface color for hover states.
  final Color surfaceHover;

  /// Surface color for active / pressed states.
  final Color surfaceActive;

  /// A very subtle surface tint, useful for zebra-striped rows or sidebars.
  final Color surfaceSubtle;

  /// Semi-transparent overlay used for modals and drawers.
  final Color overlay;

  // ── Text ─────────────────────────────────────────────────────────────────

  /// Primary text color (highest contrast).
  final Color text;

  /// Secondary / subdued text color.
  final Color textSubtle;

  /// Tertiary / muted text color (placeholders, captions).
  final Color textMuted;

  /// Inverse text color, intended for use on dark surfaces in a light scheme
  /// and vice-versa.
  final Color textInverse;

  /// Text color for content placed directly on the [primary] swatch base.
  final Color textOnPrimary;

  // ── Borders ───────────────────────────────────────────────────────────────

  /// Default border / divider color.
  final Color border;

  /// Subtle border color, lighter than [border].
  final Color borderSubtle;

  /// Border color used to indicate keyboard focus.
  final Color borderFocus;

  /// Border color used to indicate a validation error.
  final Color borderError;

  // ── Glass / frosted ───────────────────────────────────────────────────────

  /// Semi-transparent background for glass / frosted-glass effect surfaces.
  final Color glassBackground;

  /// Semi-transparent border for glass / frosted-glass effect surfaces.
  final Color glassBorder;

  // ── Chart palette ─────────────────────────────────────────────────────────

  /// An ordered list of 8 categorical colors for charts and data visualization.
  final List<Color> chart;

  // ── Utilities ─────────────────────────────────────────────────────────────

  /// Creates a copy of this scheme with the specified fields replaced.
  OiColorScheme copyWith({
    OiColorSwatch? primary,
    OiColorSwatch? accent,
    OiColorSwatch? success,
    OiColorSwatch? warning,
    OiColorSwatch? error,
    OiColorSwatch? info,
    Color? background,
    Color? surface,
    Color? surfaceHover,
    Color? surfaceActive,
    Color? surfaceSubtle,
    Color? overlay,
    Color? text,
    Color? textSubtle,
    Color? textMuted,
    Color? textInverse,
    Color? textOnPrimary,
    Color? border,
    Color? borderSubtle,
    Color? borderFocus,
    Color? borderError,
    Color? glassBackground,
    Color? glassBorder,
    List<Color>? chart,
  }) {
    return OiColorScheme(
      primary: primary ?? this.primary,
      accent: accent ?? this.accent,
      success: success ?? this.success,
      warning: warning ?? this.warning,
      error: error ?? this.error,
      info: info ?? this.info,
      background: background ?? this.background,
      surface: surface ?? this.surface,
      surfaceHover: surfaceHover ?? this.surfaceHover,
      surfaceActive: surfaceActive ?? this.surfaceActive,
      surfaceSubtle: surfaceSubtle ?? this.surfaceSubtle,
      overlay: overlay ?? this.overlay,
      text: text ?? this.text,
      textSubtle: textSubtle ?? this.textSubtle,
      textMuted: textMuted ?? this.textMuted,
      textInverse: textInverse ?? this.textInverse,
      textOnPrimary: textOnPrimary ?? this.textOnPrimary,
      border: border ?? this.border,
      borderSubtle: borderSubtle ?? this.borderSubtle,
      borderFocus: borderFocus ?? this.borderFocus,
      borderError: borderError ?? this.borderError,
      glassBackground: glassBackground ?? this.glassBackground,
      glassBorder: glassBorder ?? this.glassBorder,
      chart: chart ?? this.chart,
    );
  }

  @override
  bool operator ==(Object other) {
    if (identical(this, other)) return true;
    if (other is! OiColorScheme) return false;
    if (chart.length != other.chart.length) return false;
    for (var i = 0; i < chart.length; i++) {
      if (chart[i] != other.chart[i]) return false;
    }
    return other.primary == primary &&
        other.accent == accent &&
        other.success == success &&
        other.warning == warning &&
        other.error == error &&
        other.info == info &&
        other.background == background &&
        other.surface == surface &&
        other.surfaceHover == surfaceHover &&
        other.surfaceActive == surfaceActive &&
        other.surfaceSubtle == surfaceSubtle &&
        other.overlay == overlay &&
        other.text == text &&
        other.textSubtle == textSubtle &&
        other.textMuted == textMuted &&
        other.textInverse == textInverse &&
        other.textOnPrimary == textOnPrimary &&
        other.border == border &&
        other.borderSubtle == borderSubtle &&
        other.borderFocus == borderFocus &&
        other.borderError == borderError &&
        other.glassBackground == glassBackground &&
        other.glassBorder == glassBorder;
  }

  @override
  int get hashCode => Object.hashAll([
    primary,
    accent,
    success,
    warning,
    error,
    info,
    background,
    surface,
    surfaceHover,
    surfaceActive,
    surfaceSubtle,
    overlay,
    text,
    textSubtle,
    textMuted,
    textInverse,
    textOnPrimary,
    border,
    borderSubtle,
    borderFocus,
    borderError,
    glassBackground,
    glassBorder,
    ...chart,
  ]);

  @override
  String toString() =>
      'OiColorScheme(background: $background, '
      'surface: $surface, primary: $primary)';
}

import 'package:flutter/foundation.dart';
import 'package:flutter/painting.dart';

/// A color token with five semantic shade variants.
///
/// Each swatch represents a single brand/semantic color with automatically
/// derived or explicitly provided shade variants. Used throughout
/// [OiColorScheme] to represent primary, accent, success, warning, error,
/// and info colors.
///
/// {@category Foundation}
@immutable
class OiColorSwatch {
  /// Creates an [OiColorSwatch] with explicit shade values.
  const OiColorSwatch({
    required this.base,
    required this.light,
    required this.dark,
    required this.muted,
    required this.foreground,
  });

  /// Derives shade variants from [base] using HSL color manipulation.
  ///
  /// - [light]: increased lightness (+20%)
  /// - [dark]: decreased lightness (-20%)
  /// - [muted]: desaturated to 40%, increased lightness (+30%)
  /// - [foreground]: white or black depending on contrast with [base]
  factory OiColorSwatch.from(Color base) {
    final hsl = HSLColor.fromColor(base);
    final light = hsl
        .withLightness((hsl.lightness + 0.20).clamp(0.0, 1.0))
        .toColor();
    final dark = hsl
        .withLightness((hsl.lightness - 0.20).clamp(0.0, 1.0))
        .toColor();
    final muted = hsl
        .withSaturation((hsl.saturation * 0.4).clamp(0.0, 1.0))
        .withLightness((hsl.lightness + 0.30).clamp(0.0, 1.0))
        .toColor();
    // WCAG contrast: use white on dark backgrounds, black on light.
    final luminance = base.computeLuminance();
    final foreground = luminance < 0.35
        ? const Color(0xFFFFFFFF)
        : const Color(0xFF000000);
    return OiColorSwatch(
      base: base,
      light: light,
      dark: dark,
      muted: muted,
      foreground: foreground,
    );
  }

  /// Linearly interpolates between two [OiColorSwatch]es.
  ///
  /// [t] must be in the range [0, 1]. At [t] = 0 the result equals [a];
  /// at [t] = 1 the result equals [b].
  OiColorSwatch.lerp(OiColorSwatch a, OiColorSwatch b, double t)
    : base = Color.lerp(a.base, b.base, t)!,
      light = Color.lerp(a.light, b.light, t)!,
      dark = Color.lerp(a.dark, b.dark, t)!,
      muted = Color.lerp(a.muted, b.muted, t)!,
      foreground = Color.lerp(a.foreground, b.foreground, t)!;

  /// The primary/base shade.
  final Color base;

  /// A lighter variant, suitable for backgrounds and hover states.
  final Color light;

  /// A darker variant, suitable for pressed/active states.
  final Color dark;

  /// A muted/desaturated variant, suitable for disabled or subtle contexts.
  final Color muted;

  /// A foreground color (white or black) with sufficient contrast over [base].
  final Color foreground;

  /// Creates a copy with optionally overridden fields.
  OiColorSwatch copyWith({
    Color? base,
    Color? light,
    Color? dark,
    Color? muted,
    Color? foreground,
  }) {
    return OiColorSwatch(
      base: base ?? this.base,
      light: light ?? this.light,
      dark: dark ?? this.dark,
      muted: muted ?? this.muted,
      foreground: foreground ?? this.foreground,
    );
  }

  @override
  bool operator ==(Object other) {
    if (identical(this, other)) return true;
    return other is OiColorSwatch &&
        other.base == base &&
        other.light == light &&
        other.dark == dark &&
        other.muted == muted &&
        other.foreground == foreground;
  }

  @override
  int get hashCode => Object.hash(base, light, dark, muted, foreground);

  @override
  String toString() =>
      'OiColorSwatch('
      'base: $base, '
      'light: $light, '
      'dark: $dark, '
      'muted: $muted, '
      'foreground: $foreground)';
}
